import { useState, useEffect } from "react";

const ResultPage = () => {
  const [sharedFormData, setSharedFormData] = useState({});
  const [sharedRows, setSharedRows] = useState([[]]);
  const [saveCoActivity, setSaveCoActivity] = useState([]);
  const [saveExActivity, setSaveExActivity] = useState([]);

  useEffect(() => {
    const data = localStorage.getItem("form_data");
    if (data) {
      setSharedFormData(JSON.parse(data));
    }
    const rows = localStorage.getItem("table_rows");
    if (rows) {
      setSharedRows(JSON.parse(rows));
    }
    const coActivity = localStorage.getItem("coscholastic_data");
    if (coActivity) {
      setSaveCoActivity(JSON.parse(coActivity));
    }
    const exActivity = localStorage.getItem("exactivity_data");
    if (exActivity) {
      setSaveExActivity(JSON.parse(exActivity));
    }
  }, []);

  const pageStyle = {
    height: "28.5cm",
    width: "20.8cm",
    margin: "0.5cm auto",
  };

  const generatePDF = async () => {
    const element = document.getElementById("content");
    const options = {
      margin: [0, 0, 0, 0],
      filename: "statement_of_marks.pdf",
      image: { type: "jpeg", quality: 0.98 },
      html2canvas: { scale: 3, useCORS: true },
      jsPDF: { unit: "in", format: "a4", orientation: "portrait" },
    };
    window.html2pdf().set(options).from(element).save();
  };

  return (
    <div>
      <div className="bg-gray-100 p-4">
        <div
          id="content"
          className="max-w-4xl mx-auto bg-white p-4 shadow-md relative page border-4 border-red-500"
          style={pageStyle}
        >
          <div className="absolute inset-0 flex items-center justify-center opacity-10">
            <img
              className="w-3/4 h-auto"
              src="data:image/png;base64,"
              alt="Base64 Example"
            />
          </div>

          <div className="relative z-10">
            <div className="flex justify-between items-center mb-3">
              <img
                src="data:image/png;base64,"
                alt="Base64 Example"
              />
              <div className="text-center flex-1 mx-8">
                <h1 className="text-red-600 text-xl font-bold">
                  ST. ‘N’ PUBLIC SCHOOL
                </h1>
                <p className="text-sm">69, Prempuri, Idgah, Muzaffarnagar</p>
                <p className="text-sm bg-yellow-300 inline-block px-2">
                  AFFILIATED TO ANGLO INDIAN, LUCKNOW
                </p>
              </div>
              <img
                src="data:image/png;base64,"
                alt="Base64 Example"
              />
            </div>
            <div className="flex justify-center text-sm space-x-12">
              <p>Phone No:&nbsp;+9897732421</p>
              <p>
                E-mail:&nbsp;
                <a className="text-blue-600" href="mailto:stn.mzn@gmail.com">
                  stn.mzn@gmail.com
                </a>
              </p>
            </div>
            <hr className="border-t-2 border-red-600 my-2" />
            <h2 className="text-center text-blue-700 text-lg font-bold">
              REPORT CARD
            </h2>
            <p className="text-center text-blue-700 text-xs font-bold mb-3">
              ( Issued by School as Per Directives of Central Board of Secondary
              Education, Delhi )
            </p>
            <div className="flex justify-between text-xs mb-2">
              <div>
                <p>
                  <span className="font-bold">Name:&nbsp;</span>
                  <span className="font-bold">
                    {sharedFormData.student_name}
                  </span>
                </p>
                <p>
                  <span className="font-bold">Father’s Name:&nbsp;</span>
                  <span className="font-bold">
                    Mr. {sharedFormData.father_name}
                  </span>
                </p>
                <p>
                  <span className="font-bold">SR. Number:&nbsp;</span>
                  <span className="font-bold">{sharedFormData.sr_number}</span>
                </p>
              </div>
              <div>
                <p>
                  <span className="font-bold">className:&nbsp;</span>
                  <span className="font-bold">{sharedFormData.class}</span>
                </p>
                <p>
                  <span className="font-bold">Mother’s Name:&nbsp;</span>
                  <span className="font-bold">
                    Mrs. {sharedFormData.mother_name}
                  </span>
                </p>
                <p>
                  <span className="font-bold">Roll Number:&nbsp;</span>
                  <span className="font-bold">
                    {sharedFormData.roll_number}
                  </span>
                </p>
              </div>
            </div>

            <h2 className="text-sm font-bold text-center">
              Academic Performance : Scholastic Areas
            </h2>
            <table className="w-full border-collapse mb-1 text-center text-xs border-black">
              <thead>
                <tr>
                  <th className="border px-0.5 py-1">Subjects</th>
                  <th className="border px-0.5 py-1">1st Unit Test (40)</th>
                  <th className="border px-0.5 py-1">Exam Marks (50)</th>
                  <th className="border px-0.5 py-1">Practical (10)</th>
                  <th className="border px-0.5 py-1">Marks Obtained (100)</th>
                  <th className="border px-0.5 py-1">2nd Unit Test (40)</th>
                  <th className="border px-0.5 py-1">Exam Marks (50)</th>
                  <th className="border px-0.5 py-1">Practical (10)</th>
                  <th className="border px-0.5 py-1">Marks Obtained (100)</th>
                  <th className="border px-0.5 py-1">Grand Total (200)</th>
                  <th className="border px-0.5 py-1">Grade</th>
                </tr>
              </thead>
              <tbody>
                {sharedRows.map((row, rowIndex) => (
                  <tr key={rowIndex}>
                    {row.map((cell, cellIndex) => (
                      <td
                        key={cellIndex}
                        className="border border-black py-0.5 px-1 leading-tight font-bold"
                      >
                        {cell}
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>

            <h2 className="text-sm font-bold text-center">
              Co-Scholastic Areas
            </h2>

            {saveCoActivity.length > 0 && (
              <div className="flex justify-center">
                <table className="w-3/4 border-collapse mb-1 text-xs text-center border-black">
                  <thead>
                    <tr>
                      <th className="border p-1">Activity</th>
                      <th className="border p-1">Grade</th>
                      <th className="border p-1">Activites</th>
                      <th className="border p-1">Grade</th>
                    </tr>
                  </thead>
                  <tbody>
                    {saveCoActivity.map((pair, index) => (
                      <tr key={index}>
                        <td className="border border-black py-0.5 px-2 leading-tight">
                          {pair[0].activity}
                        </td>
                        <td className="border border-black py-0.5 px-2 leading-tight">
                          {pair[0].grade}
                        </td>
                        <td className="border border-black py-0.5 px-2 leading-tight">
                          {pair[1]?.activity || "-"}
                        </td>
                        <td className="border border-black py-0.5 px-2 leading-tight">
                          {pair[1]?.grade || "-"}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}

            <h2 className="text-sm font-bold text-center">
              Extra curricular activities
            </h2>

            {saveExActivity.length > 0 && (
              <div className="flex justify-center">
                <table className="w-3/4 border-collapse mb-1 text-xs text-center border-black">
                  <thead>
                    <tr>
                      <th className="border p-1">Activity</th>
                      <th className="border p-1">Grade</th>
                      <th className="border p-1">Activites</th>
                      <th className="border p-1">Grade</th>
                    </tr>
                  </thead>
                  <tbody>
                    {saveExActivity.map((pair, index) => (
                      <tr key={index}>
                        <td className="border border-black py-0.5 px-2 leading-tight">
                          {pair[0].activity}
                        </td>
                        <td className="border border-black py-0.5 px-2 leading-tight">
                          {pair[0].grade}
                        </td>
                        <td className="border border-black py-0.5 px-2 leading-tight">
                          {pair[1]?.activity || "-"}
                        </td>
                        <td className="border border-black py-0.5 px-2 leading-tight">
                          {pair[1]?.grade || "-"}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}

            <h2 className="text-sm font-bold text-center">Attendance</h2>
            <div className="flex justify-center">
              <table className="w-3/4 border-collapse mb-1 text-xs border-black">
                <thead>
                  <tr>
                    <th className="border py-0.5 px-2 leading-tight">
                      TOTAL ATTENDANCE - {sharedFormData.total_attendance}
                    </th>
                    <th className="border py-0.5 px-2 leading-tight">
                      ATTENDING DAYS - {sharedFormData.attending_days}
                    </th>
                  </tr>
                </thead>
              </table>
            </div>

            <div className="flex justify-center items-center text-center text-xs mt-2">
              <p className="font-bold">
                Class Teacher's Remarks&nbsp;-&nbsp;
                {sharedFormData.teacher_remark}
              </p>
            </div>

            <div className="mb-2 text-xs">
              <div className="mb-8">
                <br />
                <br />
                <br />
              </div>
              <div className="flex justify-between items-center">
                <p>
                  <strong>Class Teacher's Signature</strong>
                </p>
                <p className="text-center">
                  <strong>Principal's Signature</strong>
                </p>
              </div>
            </div>
          </div>
        </div>

        <div className="text-center mt-4">
          <button
            className="bg-blue-500 text-white px-4 py-2 rounded"
            onClick={generatePDF}
          >
            Generate PDF
          </button>
        </div>
      </div>
    </div>
  );
};

export default ResultPage;
